function parseRange(s) {
  const parts = s.split('-');

  if (parts.length === 1) {
    return [parseInt(parts[0], 10)];
  }

  if (parts.length === 2) {
    const a = parseInt(parts[0], 10);
    const b = parseInt(parts[1], 10);
    const result = [];
    const step = a <= b ? 1 : -1;

    for (let i = a; step > 0 ? i <= b : i >= b; i += step) {
      result.push(i);
    }

    return result;
  }

  throw new Error('Invalid range format');
}
